import loginService from "./loginService";
import { LoginReq, CheckEmailRes, LoginRes } from "./loginTypes";

export async function login(
	email: string,
	password: string
): Promise<LoginRes> {
	return loginService.login({ email, password }).then((response) => response);
}

export async function logout(): Promise<void> {
	return loginService.logout();
}

export async function isLogged(): Promise<void> {
	return loginService.isLogged();
}

export async function checkEmail(email: string): Promise<CheckEmailRes>  {
	return loginService.checkEmail({ email }).then((response) => response);
}

const loginManager = {
	login,
	logout,
	isLogged,
	checkEmail
};

export default loginManager;
